const item = $input.first().json;
const isDbError = item.error && typeof item.error === 'object' && item.error.message;

if (isDbError) {
  return [{ json: { report: '🔴 DATA RETENTION — DB ERROR\n\nCleanup query failed: ' + item.error.message + '\n\nTimestamp: ' + new Date().toISOString(), isDbError: true, isLimitHit: false } }];
}

const dev = parseInt(item.deleted_events_count) || 0;
const circuitReset = item.stale_circuit_reset === true || item.stale_circuit_reset === 't';
const isLimitHit = dev >= 1000;

let report = `🧹 DATA RETENTION REPORT — V1 Lean\n\nDeleted Events (90d): ${dev}`;

if (circuitReset) {
  report += '\n\n⚠️ STALE CIRCUIT RESET: Circuit was open for >1 hour with no new errors. Auto-reset to closed.';
}

if (isLimitHit) {
  report += '\n\n⚠️ LIMIT HIT — Events table hit the 1000-row deletion cap. Run retention again or increase LIMIT.';
}

report += '\n\nTimestamp: ' + new Date().toISOString();

return [{ json: { report, isDbError: false, isLimitHit } }];

const item = $input.first().json;
const evalReport = $('Evaluate Cleanup').first().json.report;
const analyzeError = item.error && typeof item.error === 'object' && item.error.message;
let report = evalReport;
if (analyzeError) report += '\n\n⚠️ ANALYZE FAILED: ' + item.error.message;
else report += '\n\n✅ ANALYZE completed successfully.';
return [{ json: { report } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.eventFailures) staticData.eventFailures = [];
staticData.eventFailures.push({
  timestamp: new Date().toISOString(),
  event: 'retention_telegram_alert_failed',
  source: 'Data Retention',
  error: 'Telegram delivery failed'
});
if (staticData.eventFailures.length > 50) {
  staticData.droppedCacheCount = (staticData.droppedCacheCount || 0) + (staticData.eventFailures.length - 50);
  staticData.eventFailures = staticData.eventFailures.slice(-50);
}
return [{ json: { cached: true } }];
